    const studyGuide = await this.generateStudyGuide(questions, studentProfile);
    const examId = this.generateId();
    return {
      exam: {
        id: examId,
        questions,
        metadata
      },
      bloomsAnalysis,
      adaptiveSettings,
      studyGuide
    };
